// Normalize inbound Telegram update. No secrets persisted.
const raw = $input.item.json || {};
const cq = raw.callback_query || {};
const msg = cq.message || raw.message || {};
const data = String(cq.data || msg.text || '').trim();
const inbound_kind = data.startsWith('note:') ? 'note' : (data.startsWith('dp:') ? 'callback' : 'unknown');
return {
  json: {
    inbound_kind,
    callback_data: data,
    telegram_update_id: raw.update_id ?? null,
    chat_id_redacted: 'REDACTED_CHAT_ID',
    user_id_redacted: 'REDACTED_USER_ID',
    message_id: msg.message_id ?? null,
    received_at: new Date().toISOString(),
    test_only: true,
    note: 'Normalized inbound — configure allowed chat in UI before live gate'
  }
};

// Optional free-text note path — design/placeholder only; not active in package.
const d = $input.item.json;
const noteMatch = String(d.callback_data || '').match(/^note:(D-\d{4}-[A-Z]):(.+)$/);
const decision_id = noteMatch ? noteMatch[1] : null;
const note_text = noteMatch ? String(noteMatch[2]).slice(0, 500) : '';
return {
  json: {
    status: 'note_placeholder',
    decision_id,
    note_present: !!note_text,
    note_length: note_text.length,
    note_sanitized_preview: note_text ? '[redacted note text]' : null,
    duplicate_or_stale: false,
    test_only: true,
    receipt: 'NOTE PATH PLACEHOLDER — free-text note does not change selected option; configure in future live gate'
  }
};

// Validate allowed chat, decision_id, option 1/2/3; duplicate/stale/idempotency guard.
const d = $input.item.json;
const ALLOWED_CHAT = '**CONFIGURE_ALLOWED_CHAT_ID_IN_N8N_UI**';
const STATE_STORE = '**CONFIGURE_DECISION_STATE_STORE_IN_N8N_UI**';
const TTL_SECONDS_PLACEHOLDER = 86400;
const OPEN_TEST_DECISIONS = ['D-9998-T'];
const seen = $getWorkflowStaticData('global');
if (!seen.handledDecisionIds) seen.handledDecisionIds = {};
const chatConfigured = ALLOWED_CHAT.indexOf('CONFIGURE') === -1;
const chatOk = chatConfigured;
const m = String(d.callback_data || '').match(/^dp:(D-\d{4}-[A-Z]):([123])$/);
let status = 'blocked';
let decision_id = null;
let selected_option = null;
let duplicate_or_stale = false;
let block_reason = 'invalid_callback_data';
if (!chatOk) block_reason = 'allowed_chat_not_configured';
if (m && chatOk) {
  decision_id = m[1];
  selected_option = m[2];
  const idKey = decision_id + ':' + selected_option;
  if (!OPEN_TEST_DECISIONS.includes(decision_id)) {
    duplicate_or_stale = true;
    block_reason = 'stale_or_unknown_decision_id';
  } else if (seen.handledDecisionIds[idKey]) {
    duplicate_or_stale = true;
    block_reason = 'duplicate_or_double_click';
  } else {
    seen.handledDecisionIds[idKey] = d.received_at;
    status = 'accepted';
    block_reason = null;
  }
}
return {
  json: {
    status,
    decision_id,
    selected_option,
    callback_data: d.callback_data,
    duplicate_or_stale,
    block_reason,
    state_store_placeholder: STATE_STORE,
    ttl_seconds_placeholder: TTL_SECONDS_PLACEHOLDER,
    chat_id_redacted: d.chat_id_redacted,
    user_id_redacted: d.user_id_redacted,
    message_id: d.message_id,
    received_at: d.received_at,
    test_only: true
  }
};

// Sanitized decision receipt — valid inline button 1/2/3.
const d = $input.item.json;
return {
  json: {
    status: 'accepted',
    receipt_type: 'decision_button',
    decision_id: d.decision_id,
    selected_option: d.selected_option,
    callback_data: d.callback_data,
    duplicate_or_stale: false,
    note_present: false,
    test_only: true,
    message_id: d.message_id,
    received_at: d.received_at,
    note: 'Valid TEST ONLY decision receipt — no operational action'
  }
};

// Sanitized receipt — invalid, stale, duplicate, or blocked.
const d = $input.item.json;
return {
  json: {
    status: 'blocked',
    receipt_type: 'ignored',
    decision_id: d.decision_id,
    selected_option: d.selected_option,
    callback_data: d.callback_data,
    duplicate_or_stale: d.duplicate_or_stale,
    block_reason: d.block_reason || 'invalid',
    note_present: false,
    test_only: true,
    message_id: d.message_id,
    received_at: d.received_at,
    note: 'Inbound ignored — no operational action'
  }
};

// Read-only inspect inbound result. No secrets.
const d = $input.item.json;
return {
  json: {
    inspect_status: d.status || d.receipt_type,
    decision_id: d.decision_id || null,
    selected_option: d.selected_option || null,
    duplicate_or_stale: d.duplicate_or_stale || false,
    note_present: d.note_present || false,
    test_only: true,
    note: 'We inbound gate result — sanitize before recording'
  }
};
